function action_actor_insert(&$error_message = '') {
	global $Translation;

	// mm: can member insert record?
	$arrPerm = getTablePermissions('action_actor');
	if(!$arrPerm['insert']) {
		$error_message = $Translation['no insert permission'];
		return false;
	}

	$data = [
		'actor_ID' => Request::val('actor_ID', ''),
		'actor' => Request::lookup('actor', ''),
		'action_status' => Request::val('action_status', ''),
		'created_by' => parseCode('<%%creatorUsername%%>', true),
		'created_at' => parseCode('<%%creationDateTime%%>', true),
	];

	// record owner is current user
	$recordOwner = getLoggedMemberID();

	$recID = tableInsert('action_actor', $data, $recordOwner, $error_message);

	// if this record is a copy of another record, copy children if applicable
	if(strlen(Request::val('SelectedID')) && $recID !== false)
		action_actor_copy_children($recID, Request::val('SelectedID'));

	return $recID;
}

function action_actor_copy_children($destination_id, $source_id) {
	global $Translation;
	$requests = []; // array of curl handlers for launching insert requests
	$eo = ['silentErrors' => true];
	$safe_sid = makeSafe($source_id);
	$currentUsername = getLoggedMemberID();
	$errorMessage = '';

	// launch requests, asynchronously
	curl_batch($requests);
}

function action_actor_delete($selected_id, $AllowDeleteOfParents = false, $skipChecks = false) {
	// insure referential integrity ...
	global $Translation;
	$selected_id = makeSafe($selected_id);

	// mm: can member delete record?
	if(!check_record_permission('action_actor', $selected_id, 'delete')) {
		return $Translation['You don\'t have enough permissions to delete this record'];
	}

	// hook: action_actor_before_delete
	if(function_exists('action_actor_before_delete')) {
		$args = [];
		if(!action_actor_before_delete($selected_id, $skipChecks, getMemberInfo(), $args))
			return $Translation['Couldn\'t delete this record'] . (
				!empty($args['error_message']) ?
					'<div class="text-bold">' . strip_tags($args['error_message']) . '</div>'
					: ''
			);
	}

	sql("DELETE FROM `action_actor` WHERE `actor_ID`='{$selected_id}'", $eo);

	// hook: action_actor_after_delete
	if(function_exists('action_actor_after_delete')) {
		$args = [];
		action_actor_after_delete($selected_id, getMemberInfo(), $args);
	}

	// mm: delete ownership data
	sql("DELETE FROM `membership_userrecords` WHERE `tableName`='action_actor' AND `pkValue`='{$selected_id}'", $eo);
}

function action_actor_update(&$selected_id, &$error_message = '') {
	global $Translation;

	// mm: can member edit record?
	if(!check_record_permission('action_actor', $selected_id, 'edit')) return false;

	$data = [
		'actor_ID' => Request::val('actor_ID', ''),
		'actor' => Request::lookup('actor', ''),
		'action_status' => Request::val('action_status', ''),
		'last_updated_by' => parseCode('<%%editorUsername%%>', false),
		'last_updated_at' => parseCode('<%%editingDateTime%%>', false),
	];

	if($data['actor_ID'] === '') {
		echo StyleSheet() . "\n\n<div class=\"alert alert-danger\">{$Translation['error:']} 'ID': {$Translation['field not null']}<br><br>";
		echo '<a href="" onclick="history.go(-1); return false;">' . $Translation['< back'] . '</a></div>';
		exit;
	}
	// get existing values
	$old_data = getRecord('action_actor', $selected_id);
	if(is_array($old_data)) {
		$old_data = array_map('makeSafe', $old_data);
		$old_data['selectedID'] = makeSafe($selected_id);
	}

	$data['selectedID'] = makeSafe($selected_id);

	// hook: action_actor_before_update
	if(function_exists('action_actor_before_update')) {
		$args = ['old_data' => $old_data];
		if(!action_actor_before_update($data, getMemberInfo(), $args)) {
			if(isset($args['error_message'])) $error_message = $args['error_message'];
			return false;
		}
	}

	$set = $data; unset($set['selectedID']);
	foreach ($set as $field => $value) {
		$set[$field] = ($value !== '' && $value !== NULL) ? $value : NULL;
	}

	if(!update(
		'action_actor',
		backtick_keys_once($set),
		['`actor_ID`' => $selected_id],
		$error_message
	)) {
		echo $error_message;
		echo '<a href="action_actor_view.php?SelectedID=' . urlencode($selected_id) . "\">{$Translation['< back']}</a>";
		exit;
	}

	$data['selectedID'] = $data['actor_ID'];
	$newID = $data['actor_ID'];

	update_calc_fields('action_actor', $data['selectedID'], calculated_fields()['action_actor']);

	// hook: action_actor_after_update
	if(function_exists('action_actor_after_update')) {
		if($row = getRecord('action_actor', $data['selectedID'])) $data = array_map('makeSafe', $row);

		$data['selectedID'] = $data['actor_ID'];
		$args = ['old_data' => $old_data];
		if(!action_actor_after_update($data, getMemberInfo(), $args)) return;
	}

	// mm: update record update timestamp
	set_record_owner('action_actor', $selected_id);

	// if PK value changed, update ownership and $selected_id
	if($selected_id != $newID) {
		update('membership_userrecords', ['pkValue' => $newID], ['pkValue' => $selected_id, 'tableName' => 'action_actor']);
		$selected_id = $newID;
	}
}

